const raw = $input.first().json.output;
const parsed = JSON.parse(raw);
const frameworks = ["porter","rumelt","christensen","blue_ocean","effectuation","jtbd","lean_startup","behavioural","sharp"];
const items = frameworks.map(fw => ({
  json: {
    framework: fw,
    prompt: parsed.tasks[fw],
    problem_summary: parsed.problem_summary,
    synthesis_context: parsed.synthesis_context
  }
}));
return items;

const items = $input.all();
const r1 = {};
const synCtx = items[0].json.synthesis_context || "";
const probSummary = items[0].json.problem_summary || "";
for (const it of items) {
  r1[it.json.framework] = it.json.output;
}
const R2C = {"porter": ["blue_ocean", "jtbd"], "rumelt": ["porter", "lean_startup"], "christensen": ["porter", "sharp"], "blue_ocean": ["porter", "behavioural"], "effectuation": ["lean_startup", "christensen"], "jtbd": ["sharp", "porter"], "lean_startup": ["rumelt", "effectuation"], "behavioural": ["porter", "christensen"], "sharp": ["blue_ocean", "jtbd"]};
const labels = {porter:"Porter",rumelt:"Rumelt",christensen:"Christensen",blue_ocean:"Blue Ocean",effectuation:"Effectuation",jtbd:"JTBD",lean_startup:"Lean Startup",behavioural:"Behavioural Strategy",sharp:"Byron Sharp"};
return Object.keys(R2C).map(fw => {
  const [c1, c2] = R2C[fw];
  const prompt = `TWOJA ANALIZA Z RUNDY 1:
${r1[fw]}

---
RUNDA 2: CROSS-EXAMINATION
Twoim zadaniem jest KRYTYCZNA ANALIZA poniższych dwóch perspektyw z Twojego frameworku.

PERSPEKTYWA ${labels[c1].toUpperCase()}:
${r1[c1]}

PERSPEKTYWA ${labels[c2].toUpperCase()}:
${r1[c2]}

Wskaż konkretnie:
1. Co ${labels[c1]} pomija / błędnie definiuje patrząc z Twojej perspektywy?
2. Co ${labels[c2]} pomija / błędnie definiuje patrząc z Twojej perspektywy?
3. Gdzie Twoja analiza i ich analizy są zbieżne (jeśli gdziekolwiek)?
4. Jakie ukryte założenia widzisz w ich podejściach?

Bądź precyzyjny i merytoryczny. Nie bądź dyplomatyczny — to jest debata.`;
  return {
    json: {
      framework: fw,
      prompt,
      problem_summary: probSummary,
      synthesis_context: synCtx,
      r1_outputs: r1
    }
  };
});

const items = $input.all();
const r2 = {};
let r1 = {};
let synCtx = "";
let probSummary = "";
for (const it of items) {
  r2[it.json.framework] = it.json.output;
  if (it.json.r1_outputs) r1 = it.json.r1_outputs;
  if (it.json.synthesis_context) synCtx = it.json.synthesis_context;
  if (it.json.problem_summary) probSummary = it.json.problem_summary;
}
const labels = {porter:"Porter",rumelt:"Rumelt",christensen:"Christensen",blue_ocean:"Blue Ocean",effectuation:"Effectuation",jtbd:"JTBD",lean_startup:"Lean Startup",behavioural:"Behavioural Strategy",sharp:"Byron Sharp"};
return Object.keys(r2).map(fw => {
  const otherCritiques = Object.entries(r2)
    .filter(([k]) => k !== fw)
    .map(([k, v]) => `--- ${labels[k].toUpperCase()} (runda 2):\n${v}`)
    .join("\n\n");
  const prompt = `TWOJA ANALIZA Z RUNDY 1:
${r1[fw]}

TWOJA KRYTYKA Z RUNDY 2:
${r2[fw]}

---
RUNDA 3: AKTUALIZACJA STANOWISKA

Zapoznaj się z tym, co powiedzieli inni eksperci w rundzie 2:

${otherCritiques}

Teraz:
1. Zaktualizuj swoją ocenę pewności (X/10) z rundy 1 na podstawie argumentów innych. Jeśli argumenty Cię przekonały — zmień. Jeśli nie — uzasadnij dlaczego nie.
2. Czy zmieniasz jakieś elementy swojej rekomendacji? Co i dlaczego?
3. Wskaż który ekspert podniósł najsilniejszy argument (nawet jeśli się nie zgadzasz) i dlaczego.
4. Co pozostaje Twoim kluczowym, niezmienionym przekonaniem?

Format:
OCENA PEWNOŚCI: [stara] → [nowa] / [uzasadnienie zmiany lub jej braku]
ZMIANY W REKOMENDACJI: [opis lub "brak zmian"]
NAJSILNIEJSZY ARGUMENT PRZECIWNY: [ekspert + argument]
MOJE NIEZACHWIANE PRZEKONANIE: [co zostaje]
FINALNA POZYCJA: [streszczenie Twojego stanowiska po rundzie 3]`;
  return {
    json: {
      framework: fw,
      prompt,
      problem_summary: probSummary,
      synthesis_context: synCtx,
      r1_outputs: r1,
      r2_outputs: r2
    }
  };
});

const items = $input.all();
const r3 = {};
let r1 = {}, r2 = {};
let synCtx = "", probSummary = "";
for (const it of items) {
  r3[it.json.framework] = it.json.output;
  if (it.json.r1_outputs) r1 = it.json.r1_outputs;
  if (it.json.r2_outputs) r2 = it.json.r2_outputs;
  if (it.json.synthesis_context) synCtx = it.json.synthesis_context;
  if (it.json.problem_summary) probSummary = it.json.problem_summary;
}
const labels = {porter:"Porter",rumelt:"Rumelt",christensen:"Christensen",blue_ocean:"Blue Ocean",effectuation:"Effectuation",jtbd:"JTBD",lean_startup:"Lean Startup",behavioural:"Behavioural Strategy",sharp:"Byron Sharp"};
const r1_block = Object.entries(r1).map(([k,v]) => `=== ${labels[k]} — RUNDA 1 ===\n${v}`).join("\n\n");
const r2_block = Object.entries(r2).map(([k,v]) => `=== ${labels[k]} — RUNDA 2 ===\n${v}`).join("\n\n");
const r3_block = Object.entries(r3).map(([k,v]) => `=== ${labels[k]} — RUNDA 3 (FINALNA) ===\n${v}`).join("\n\n");
return {
  json: {
    problem_summary: probSummary,
    synthesis_context: synCtx,
    r1_block, r2_block, r3_block
  }
};

const synthesis = $('Synthesis').first().json.output;
const meta = $input.first().json.output;
const r1 = $('PrepareSynthesis').first().json.r1_block;
const r2 = $('PrepareSynthesis').first().json.r2_block;
const r3 = $('PrepareSynthesis').first().json.r3_block;
const prob = $('PrepareSynthesis').first().json.problem_summary;
const divider = "═".repeat(60);
const output = `${divider}
STRATEGIC DEBATE ENGINE — PEŁNY RAPORT
${divider}

PROBLEM STRATEGICZNY:
${prob}

${divider}
RUNDA 1 — DIAGNOZY EKSPERTÓW
${divider}
${r1}

${divider}
RUNDA 2 — CROSS-EXAMINATION
${divider}
${r2}

${divider}
RUNDA 3 — ZAKTUALIZOWANE STANOWISKA
${divider}
${r3}

${divider}
MAPA DEBATY I REKOMENDACJA SYNTETYCZNA
${divider}
${synthesis}

${divider}
META-ANALIZA DEBATY
${divider}
${meta}
`;
return { json: { output } };
